import React from 'react';
import styled from 'styled-components';

const HeroSection = styled.section`
  padding: 5rem 2rem 4rem;
  text-align: center;
  background: linear-gradient(135deg, #f8f9fa 0%, #f1f3f9 100%);
`;

const ContentWrapper = styled.div`
  max-width: 820px;
  margin: 0 auto;
`;

const ProfilePhoto = styled.img`
  width: 160px;
  height: 160px;
  border-radius: 50%;
  margin: 0 auto 1.8rem;
  display: block;
  object-fit: cover;
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);
  border: 4px solid #ffffff;
`;

const Eyebrow = styled.p`
  font-size: 1.05rem;
  color: #667eea;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  margin-bottom: 0.6rem;
`;

const MainHeading = styled.h1`
  font-size: 3rem;
  line-height: 1.1;
  color: #1a1a1a;
  margin-bottom: 1rem;
  font-weight: 700;
`;

const Subtitle = styled.p`
  font-size: 1.25rem;
  color: #475569;
  line-height: 1.65;
  max-width: 680px;
  margin: 0 auto 2.5rem;
`;

const CTAContainer = styled.div`
  display: flex;
  justify-content: center;
  gap: 1.2rem;
  flex-wrap: wrap;
`;

const PrimaryButton = styled.a`
  padding: 0.85rem 2rem;
  background: #667eea;
  color: #fff;
  text-decoration: none;
  border-radius: 50px;
  font-weight: 600;
  font-size: 1.05rem;
  transition: all 0.3s ease;

  &:hover {
    background: #5a67d8;
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(102, 126, 234, 0.3);
  }
`;

const SecondaryButton = styled.a`
  padding: 0.85rem 2rem;
  background: transparent;
  color: #1e2937;
  text-decoration: none;
  border: 2px solid #e2e8f0;
  border-radius: 50px;
  font-weight: 600;
  font-size: 1.05rem;
  transition: all 0.3s ease;

  &:hover {
    background: #f8fafc;
    border-color: #94a3b8;
  }
`;

// ==================== SPECIALTIES SECTION ====================

const SpecialtiesSection = styled.section`
  padding: 5rem 2rem;
  background: #ffffff;
`;

const SpecialtiesWrapper = styled.div`
  max-width: 1100px;
  margin: 0 auto;
`;

const SectionTitle = styled.h2`
  font-size: 2.4rem;
  color: #1a1a1a;
  text-align: center;
  margin-bottom: 3rem;
  font-weight: 700;
`;

const SpecialtiesGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 2rem;
`;

const SpecialtyCard = styled.div`
  padding: 2.2rem;
  background: #f8fafc;
  border-radius: 16px;
  border: 1px solid #e2e8f0;
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);

  &:hover {
    transform: translateY(-8px);
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
    border-color: #667eea;
  }
`;

const SpecialtyIcon = styled.div`
  font-size: 3rem;
  margin-bottom: 1.2rem;
`;

const SpecialtyTitle = styled.h3`
  font-size: 1.35rem;
  font-weight: 700;
  color: #1e2937;
  margin-bottom: 0.9rem;
`;

const SpecialtyDescription = styled.p`
  font-size: 1rem;
  color: #64748b;
  line-height: 1.7;
`;

const HomePage = () => (
  <>
    <HeroSection>
      <ContentWrapper>
        <ProfilePhoto
          src="/images/joel-tiogo.jpg"   // ← Put your photo in public/images/joel-tiogo.jpg
          alt="Joël Tiogo"
        />
        <Eyebrow>Business Development • AI • Circularity</Eyebrow>
        <MainHeading>Joël Tiogo</MainHeading>
        <Subtitle>
          MBA graduate and entrepreneurial leader with deep expertise in strategic business development,
          digital transformation, AI-driven solutions, and ESG/circularity strategies.
          Passionate about bridging technology and sustainable innovation in the automotive, energy,
          and enterprise sectors.
        </Subtitle>

        <CTAContainer>
          <PrimaryButton href="/about">Explore My Journey</PrimaryButton>
          <SecondaryButton href="mailto:tiogojoel@gmail.com">Get in Touch</SecondaryButton>
        </CTAContainer>
      </ContentWrapper>
    </HeroSection>

    <SpecialtiesSection>
      <SpecialtiesWrapper>
        <SectionTitle>Core Expertise</SectionTitle>
        <SpecialtiesGrid>
          <SpecialtyCard>
            <SpecialtyIcon>📈</SpecialtyIcon>
            <SpecialtyTitle>Strategic Business Development</SpecialtyTitle>
            <SpecialtyDescription>
              Driving commercial growth and unlocking new market opportunities for technology-driven companies, with a strong track record in the automotive and energy sectors.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🌱</SpecialtyIcon>
            <SpecialtyTitle>ESG & Circularity</SpecialtyTitle>
            <SpecialtyDescription>
              Leading sustainability initiatives and digital battery passport projects, helping organizations meet global ESG standards and embrace circular economy principles.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🤖</SpecialtyIcon>
            <SpecialtyTitle>AI & Machine Learning</SpecialtyTitle>
            <SpecialtyDescription>
              Designing and implementing AI/ML solutions, including computer vision systems, to solve complex business problems and enhance operational intelligence.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🔄</SpecialtyIcon>
            <SpecialtyTitle>Digital Transformation</SpecialtyTitle>
            <SpecialtyDescription>
              Guiding enterprises through digital modernization, IoT integration, and smart systems to boost efficiency and innovation.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🤝</SpecialtyIcon>
            <SpecialtyTitle>Stakeholder & Partnership Management</SpecialtyTitle>
            <SpecialtyDescription>
              Building high-trust relationships with clients, partners, and cross-functional teams to align objectives and deliver impactful results.
            </SpecialtyDescription>
          </SpecialtyCard>

          <SpecialtyCard>
            <SpecialtyIcon>🚀</SpecialtyIcon>
            <SpecialtyTitle>Entrepreneurial Leadership</SpecialtyTitle>
            <SpecialtyDescription>
              Former founder & CEO with hands-on experience scaling startups and translating technical innovation into commercial success.
            </SpecialtyDescription>
          </SpecialtyCard>
        </SpecialtiesGrid>
      </SpecialtiesWrapper>
    </SpecialtiesSection>
  </>
);

export default HomePage;
